class Solution:
    def largestGoodInteger(self, num):
        best = ''
        for i in range(len(num) - 2):
            chunk = num[i:i + 3]
            if chunk[0] == chunk[1] == chunk[2]:
                if best == '' or chunk > best:
                    best = chunk
        return best

solutions.python:
class Solution:
    def largestGoodInteger(self, num):
        best = -1
        for i in range(len(num) - 2):
            if num[i] == num[i + 1] == num[i + 2]:
                d = int(num[i])
                if d > best:
                    best = d
        return str(best) * 3 if best >= 0 else ''

solutions.javascript:
var largestGoodInteger = function(num) {
    let best = -1;
    for (let i = 0; i + 2 < num.length; i++) {
        if (num[i] === num[i + 1] && num[i + 1] === num[i + 2]) {
            const d = num.charCodeAt(i) - 48;
            if (d > best) best = d;
        }
    }
    return best >= 0 ? String(best).repeat(3) : '';
};
